import java.nio.ByteBuffer;
import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Ensure the buffer size is fixed and safe to prevent buffer overflow
        int bufferSize = 10;
        byte[] buffer = new byte[bufferSize];

        // Copy user input using ByteBuffer to ensure safe handling
        ByteBuffer byteBuffer = ByteBuffer.wrap(buffer);
        byteBuffer.put(name.getBytes(), 0, Math.min(name.length(), bufferSize));

        System.out.println("Hello, " + new String(buffer).trim());
    }
}

### Explanation:
취약유형: Buffer Overflow
